export type RenderTheme = "dark" | "light";

/** The vendored orz-markdown CSS for a render theme (default dark-elegant). */
export function themeCss(theme: RenderTheme = "dark"): string {
  return theme === "light" ? ORZ_LIGHT_NEAT_CSS : ORZ_DARK_ELEGANT_CSS;
}
